from lxml import etree
from io import StringIO

def process_soap_request(xml_string, dtd_string):
    try:
        # Parse the DTD
        dtd = etree.DTD(StringIO(dtd_string))
        
        # Parse the XML
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        xml_tree = etree.fromstring(xml_string, parser=parser)
        
        # Validate XML against DTD
        if not dtd.validate(xml_tree):
            raise ValueError("XML does not conform to DTD")
        
        # Extract the SOAP Body
        namespaces = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
        body = xml_tree.find('.//soap:Body', namespaces)
        
        if body is None:
            raise ValueError("SOAP Body not found")
        
        # Return the body content as a string
        return etree.tostring(body, pretty_print=True, encoding='unicode')
    
    except (etree.XMLSyntaxError, ValueError) as e:
        return f"Error processing SOAP request: {str(e)}"